/bin/sh -lc "python - <<'PY'
import wave, struct, math, zlib
p='/app/media/audio_engine_005.wav'
with wave.open(p,'rb') as w:
    sr=w.getframerate(); n=w.getnframes(); xs=list(struct.unpack('<%dh'%n, w.readframes(n)))
W,H=1400,420
img=[[(255,255,255) for _ in range(W)] for __ in range(H)]
def setpx(x,y,c):
    if 0<=x<W and 0<=y<H: img[y][x]=c
for t in [i*0.5 for i in range(11)]:
    x=int(t/5*W)
    for y in range(H): setpx(x,y,(220,220,220))
for y in [H//4,H//2,3*H//4]:
    for x in range(W): setpx(x,y,(230,230,230))
for x in range(W):
    a=int(x*n/W); b=max(a+1,int((x+1)*n/W)); seg=xs[a:b]
    mn=min(seg); mx=max(seg)
    y1=int(H*0.25 - mx/32768*(H*0.22)); y2=int(H*0.25 - mn/32768*(H*0.22))
    for y in range(min(y1,y2),max(y1,y2)+1): setpx(x,y,(30,80,150))
win=int(sr*0.01); rms=[]
for i in range(0,n-win+1,win): rms.append(math.sqrt(sum(v*v for v in xs[i:i+win])/win))
sm=[]
for i in range(len(rms)):
    lo=max(0,i-2); hi=min(len(rms),i+3); sm.append(sum(rms[lo:hi])/(hi-lo))
mx=max(sm); mn=min(sm)
prev=None
for i,v in enumerate(sm):
    x=int(i/(len(sm)-1)*(W-1)); y=int(H*0.93 - (v-mn)/(mx-mn)*(H*0.38))
    if prev:
        x0,y0=prev
        steps=max(abs(x-x0),abs(y-y0),1)
        for s in range(steps+1):
            xx=int(x0+(x-x0)*s/steps); yy=int(y0+(y-y0)*s/steps)
            for dy in [-1,0,1]: setpx(xx,yy+dy,(180,40,40))
    prev=(x,y)
# PNG encode
raw=bytearray()
for row in img:
    raw.append(0)
    for r,g,b in row:
        raw += bytes([r,g,b])
def chunk(t,d):
    import zlib
    return len(d).to_bytes(4,'big')+t+d+zlib.crc32(t+d).to_bytes(4,'big')
png=b'\\x89PNG\\r\\n\\x1a\\n'
png += chunk(b'IHDR', W.to_bytes(4,'big')+H.to_bytes(4,'big')+bytes([8,2,0,0,0]))
png += chunk(b'IDAT', zlib.compress(bytes(raw), 6))
png += chunk(b'IEND', b'')
open('/app/audio_diag.png','wb').write(png)
print('/app/audio_diag.png')
PY"
